1	<!DOCTYPE html>
2	<html lang="sv">
3	<head>
4	<meta charset="UTF-8">
5	<meta name="viewport" content="width=device-width, initial-scale=1">
6	<title>Widforss Shorts</title>
7	<style>
8	  @font-face { font-family: 'Bagoss Extended'; src: url('fonts/BagossExtended-Light-TRIAL.otf') format('opentype'); font-weight: 300; font-display: swap; }
9	  @font-face { font-family: 'Bagoss Extended'; src: url('fonts/BagossExtended-Regular-TRIAL.otf') format('opentype'); font-weight: 400; font-display: swap; }
10	  @font-face { font-family: 'Bagoss Extended'; src: url('fonts/BagossExtended-Medium-TRIAL.ttf') format('truetype'); font-weight: 500; font-display: swap; }
11	  @font-face { font-family: 'Bagoss Extended'; src: url('fonts/BagossExtended-SemiBold-TRIAL.ttf') format('truetype'); font-weight: 600; font-display: swap; }
12	
13	  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
14	
15	  :root {
16	    --green:       #154A29;
17	    --green-cart:  #134B2B;
18	    --strip:       #B9C275;
19	    --search-bg:   #F4F4F4;
20	    --ease-standard: cubic-bezier(0.25, 0, 0.15, 1);
21	    --ease-snappy:   cubic-bezier(0.16, 1, 0.3, 1);
22	    --gutter: clamp(40px, 7.6vw, 127px);
23	    --content-max: 1672px;
24	  }
25	
26	  html, body {
27	    background: #ffffff;
28	    color: #000;
29	    font-family: 'Bagoss Extended', system-ui, sans-serif;
30	    -webkit-font-smoothing: antialiased;
31	    -moz-osx-font-smoothing: grayscale;
32	    text-rendering: optimizeLegibility;
33	  }
34	  body {
35	    height: 100vh;
36	    overflow: hidden;
37	    display: flex;
38	    align-items: center;
39	    justify-content: center;
40	  }
41	  a { color: inherit; text-decoration: none; }
42	  button { font-family: inherit; }
43	
44	  /* Desktop frame */
45	  .desktop-frame {
46	    position: relative;
47	    width: min(var(--content-max), calc(100vw - 80px));
48	    height: calc(100vh - 80px);
49	    border-radius: 18px;
50	    overflow: hidden;
51	    box-shadow: 0 30px 80px rgba(0, 0, 0, 0.18);
52	    background: #fff;
53	  }
54	
55	  .page {
56	    background: #fff;
57	    height: 100%;
58	    overflow: hidden;
59	    display: flex;
60	    flex-direction: column;
61	  }
62	
63	  /* Utility bar */
64	  .utility-bar {
65	    background: var(--green);
66	    height: 46px;
67	    display: flex;
68	    align-items: center;
69	    padding-inline: var(--gutter);
70	    color: #fff;
71	    font-weight: 500;
72	    font-size: 12px;
73	    line-height: 1.12;
74	    letter-spacing: 0.04em;
75	    gap: 40px;
76	  }
77	  .utility-bar .right { margin-left: auto; }
78	
79	  /* Header */
80	  .site-header {
81	    display: grid;
82	    grid-template-columns: 1fr auto 1fr;
83	    align-items: center;
84	    padding: 18px var(--gutter) 15px;
85	  }
86	  .dept-nav {
87	    display: flex;
88	    align-items: center;
89	    justify-self: start;
90	    gap: 24px;
91	    font-weight: 500;
92	    font-size: 14px;
93	    line-height: 0.8;
94	    letter-spacing: 0.04em;
95	  }
96	  .dept-nav a {
97	    padding: 6px 0;
98	    transition: opacity 0.15s var(--ease-standard);
99	  }
100	  .dept-nav a:hover { opacity: 0.7; }
101	  .dept-nav a.active {
102	    background: var(--green);
103	    color: #fff;
104	    padding: 6px 16px;
105	    height: 30px;
106	    display: flex;
107	    align-items: center;
108	    border-radius: 10px;
109	  }
110	  .logo-link { justify-self: center; line-height: 0; }
111	  .logo-link img { width: 173px; height: 43px; display: block; }
112	  .header-right {
113	    display: flex;
114	    align-items: center;
115	    gap: 12px;
116	    justify-self: end;
117	  }
118	  .search-bar {
119	    background: var(--search-bg);
120	    border-radius: 8px;
121	    height: 49px;
122	    display: flex;
123	    align-items: center;
124	    padding: 0 18px;
125	    gap: 12px;
126	    width: 362px;
127	  }
128	  .search-bar input {
129	    flex: 1; min-width: 0;
130	    border: none; background: transparent;
131	    font: 300 16px/1 'Bagoss Extended', sans-serif;
132	    color: #000; outline: none;
133	    letter-spacing: 0.02em;
134	  }
135	  .search-bar input::placeholder { color: #000; opacity: 1; }
136	  .search-bar svg { flex-shrink: 0; }
137	  .cart-area { position: relative; }
138	  .cart-icon-wrap {
139	    background: none; border: none; cursor: pointer;
140	    display: flex; align-items: center; justify-content: center;
141	    padding: 4px;
142	  }
143	  .cart-badge {
144	    position: absolute; top: -4px; right: -6px;
145	    width: 18px; height: 18px;
146	    background: var(--green-cart);
147	    color: #fff;
148	    font-size: 10px;
149	    font-weight: 600;
150	    border-radius: 50%;
151	    display: grid; place-items: center;
152	  }
153	
154	  /* Nav separator */
155	  .nav-sep { height: 1px; background: #e1e1e1; }
156	
157	  /* Sub-nav */
158	  .sub-nav {
159	    display: flex;
160	    justify-content: space-between;
161	    padding: 20px var(--gutter) 15px;
162	    font-weight: 500;
163	    font-size: 14px;
164	    line-height: 0.8;
165	    letter-spacing: 0.04em;
166	  }
167	  .sub-nav nav { display: flex; gap: 32px; }
168	  .sub-nav a {
169	    padding: 4px 0;
170	    border-bottom: 2px solid transparent;
171	    transition: border-color 0.15s var(--ease-standard);
172	  }
173	  .sub-nav a:hover { border-bottom-color: rgba(0,0,0,0.3); }
174	
175	  /* Content area */
176	  .content-area {
177	    background: #000;
178	    flex: 1;
179	  }
180	</style>
181	</head>
182	<body>
183	
184	<div class="desktop-frame">
185	<div class="page">
186	
187	  <div class="utility-bar">
188	    <span>Fri frakt over 599 kr</span>
189	    <span>Delbetala med Klarna</span>
190	    <span class="right">Kontakta oss</span>
191	  </div>
192	
193	  <header class="site-header">
194	    <nav class="dept-nav">
195	      <a href="#" class="active">Jakt</a>
196	      <a href="#">Friluftsliv</a>
197	      <a href="#">Hund</a>
198	    </nav>
199	    <a href="#" class="logo-link" aria-label="Widforss"><img src="logo.svg" alt="Widforss"></a>
200	    <div class="header-right">
201	      <div class="search-bar">
202	        <input type="search" placeholder="Sok etter produkter">
203	        <svg width="20" height="20" viewBox="0 0 23 23" fill="none">
204	          <path d="M21.2864 21.2864L15.5033 15.5033M15.5033 15.5033C17.0966 13.9101 17.9913 11.7488 17.9913 9.49564C17.9913 7.24246 17.0962 5.08156 15.503 3.48832C13.9097 1.89507 11.7488 1 9.49564 1C7.24246 1 5.08156 1.89507 3.48832 3.48832C1.89507 5.08156 1 7.24246 1 9.49564C1 11.7488 1.89507 13.9097 3.48832 15.503C5.08156 17.0962 7.24246 17.9913 9.49564 17.9913C11.7488 17.9913 13.9101 17.0966 15.5033 15.5033Z" stroke="black" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/>
205	        </svg>
206	      </div>
207	      <div class="cart-area">
208	        <button class="cart-icon-wrap" aria-label="Kundvagn">
209	          <svg width="22" height="20" viewBox="0 0 22 20" fill="none">
210	            <path d="M21.7525 17.6914L20.3672 6.03461C20.3223 5.65476 20.139 5.3048 19.8522 5.05169C19.5654 4.79857 19.1954 4.66009 18.8129 4.66273H15.5459C15.5459 3.4261 15.0547 2.24011 14.1802 1.36568C13.3058 0.49125 12.1198 0 10.8832 0C9.64655 0 8.46057 0.49125 7.58614 1.36568C6.71171 2.24011 6.22046 3.4261 6.22046 4.66273H2.94929C2.56681 4.66009 2.19679 4.79857 1.91003 5.05169C1.62328 5.3048 1.43992 5.65476 1.39505 6.03461L0.0107364 17.6914C-0.015053 17.9097 0.00574536 18.131 0.0717586 18.3406C0.137772 18.5503 0.247499 18.7435 0.393696 18.9076C0.539894 19.0717 0.719237 19.203 0.919889 19.2927C1.12054 19.3824 1.33794 19.4285 1.55773 19.428H20.2014C20.4229 19.4286 20.642 19.3822 20.8442 19.2918C21.0464 19.2015 21.2271 19.0692 21.3743 18.9037C21.5192 18.7397 21.6277 18.5469 21.6929 18.338C21.7581 18.1291 21.7784 17.9087 21.7525 17.6914Z" fill="#CCCCCB"/>
211	          </svg>
212	        </button>
213	        <span class="cart-badge">1</span>
214	      </div>
215	    </div>
216	  </header>
217	
218	  <div class="nav-sep"></div>
219	
220	  <div class="sub-nav">
221	    <nav>
222	      <a href="#">Deals</a>
223	      <a href="#">Klader</a>
224	      <a href="#">Skor</a>
225	      <a href="#">Kangor &amp; Stovlar</a>
226	      <a href="#">Utrustning &amp; Tillbehor</a>
227	      <a href="#">Ata, Dricka &amp; Forvara</a>
228	    </nav>
229	    <nav>
230	      <a href="#">Guider</a>
231	      <a href="#">Varumarken</a>
232	      <a href="#">Nyheter</a>
233	    </nav>
234	  </div>
235	
236	  <div class="content-area"></div>
237	
238	</div>
239	</div>
240	
241	</body>
242	</html>
