input.new_string:
  /* Content area */
  .content-area {
    background: #1D1D1D;
    flex: 1;
    position: relative;
    display: flex;
    align-items: center;
    justify-content: center;
    overflow: hidden;
  }

  /* Shorts feed layout */
  .shorts-feed {
    position: relative;
    width: 100%;
    height: 100%;
    display: flex;
    align-items: center;
    justify-content: center;
  }

  /* Video viewport — the scrollable snap container */
  .video-viewport {
    position: relative;
    width: 100%;
    max-width: 574px;
    height: 100%;
    overflow-y: scroll;
    scroll-snap-type: y mandatory;
    scrollbar-width: none;
    -ms-overflow-style: none;
  }
  .video-viewport::-webkit-scrollbar { display: none; }

  /* Each video slide */
  .video-slide {
    position: relative;
    width: 100%;
    height: 100%;
    scroll-snap-align: center;
    scroll-snap-stop: always;
    flex-shrink: 0;
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 20px 0;
  }

  .video-card {
    position: relative;
    width: 100%;
    aspect-ratio: 574 / 1021;
    max-height: calc(100% - 40px);
    border-radius: 20px;
    overflow: hidden;
    background: #000;
  }

  .video-card video {
    position: absolute;
    inset: 0;
    width: 100%;
    height: 100%;
    object-fit: cover;
  }

  /* Gradient overlay on video */
  .video-gradient {
    position: absolute;
    inset: 0;
    background: linear-gradient(0deg, transparent 0%, rgba(0,0,0,0.74) 100%);
    pointer-events: none;
    opacity: 0;
    transition: opacity 0.4s var(--ease-standard);
  }
  .video-card:hover .video-gradient { opacity: 1; }

  /* Captions overlay at bottom of video */
  .video-captions {
    position: absolute;
    bottom: 60px;
    left: 0;
    right: 0;
    text-align: center;
    padding: 0 40px;
    pointer-events: none;
  }
  .video-captions p {
    font-family: 'Bagoss Extended', system-ui, sans-serif;
    font-weight: 600;
    font-size: 22px;
    line-height: 1.2;
    color: #fff;
    text-shadow: 0 1px 8px rgba(0,0,0,0.5);
  }

  /* Progress bar at bottom of video card */
  .video-progress {
    position: absolute;
    bottom: 16px;
    left: 24px;
    right: 24px;
    height: 4px;
    background: rgba(29, 27, 25, 0.9);
    border-radius: 16px;
    overflow: hidden;
  }
  .video-progress-fill {
    height: 100%;
    background: #7EB896;
    border-radius: 16px 0 0 16px;
    width: 0%;
    transition: width 0.1s linear;
  }

  /* Left side info panel */
  .shorts-info {
    position: absolute;
    left: 45px;
    bottom: 50%;
    transform: translateY(50%);
    z-index: 10;
    display: flex;
    flex-direction: column;
    gap: 0;
  }
  .shorts-info-title {
    font-family: 'Bagoss Extended', system-ui, sans-serif;
    font-weight: 600;
    font-size: 26px;
    line-height: 0.92;
    color: #fff;
    max-width: 200px;
    margin-bottom: 8px;
  }
  .shorts-info-time {
    font-family: 'Bagoss Extended', system-ui, sans-serif;
    font-weight: 300;
    font-size: 14px;
    color: #fff;
    opacity: 0.8;
    margin-bottom: 26px;
  }
  .shorts-info-cta {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    background: #AFCC95;
    color: #000;
    font-family: 'Bagoss Extended', system-ui, sans-serif;
    font-weight: 400;
    font-size: 14px;
    line-height: 1;
    padding: 8px 20px;
    border-radius: 15px;
    border: none;
    cursor: pointer;
    width: fit-content;
    transition: background 0.15s var(--ease-standard);
  }
  .shorts-info-cta:hover { background: #c2da ad; }

  /* Right side controls */
  .shorts-sidebar {
    position: absolute;
    right: 39px;
    top: 50%;
    transform: translateY(-50%);
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 0;
    z-index: 10;
  }

  .shorts-nav-btn {
    background: none;
    border: none;
    cursor: pointer;
    padding: 10px;
    display: flex;
    align-items: center;
    justify-content: center;
    opacity: 0.7;
    transition: opacity 0.15s var(--ease-standard);
  }
  .shorts-nav-btn:hover { opacity: 1; }
  .shorts-nav-btn svg { display: block; }

  .shorts-thumbnails {
    display: flex;
    flex-direction: column;
    gap: 18px;
    padding: 16px 0;
  }

  .shorts-thumb {
    width: 92px;
    height: 95px;
    border-radius: 20px;
    overflow: hidden;
    cursor: pointer;
    opacity: 0.32;
    transition: opacity 0.3s var(--ease-standard);
    position: relative;
  }
  .shorts-thumb.active {
    opacity: 1;
  }
  .shorts-thumb video,
  .shorts-thumb img {
    width: 100%;
    height: 100%;
    object-fit: cover;
  }

  /* Mute button */
  .shorts-mute {
    position: absolute;
    right: 72px;
    bottom: 43px;
    background: none;
    border: none;
    cursor: pointer;
    padding: 4px;
    z-index: 10;
    opacity: 0.8;
    transition: opacity 0.15s var(--ease-standard);
  }
  .shorts-mute:hover { opacity: 1; }
</style>

