<script>
(function() {
  const videos = [
    {
      src: 'SnapInsta.to_AQMvRqrxCp1k3C1N975d91bavqYCYKMBul9Kktj2yqpILzdCkufZH_Ks_FaeOseu6n3sbgnOE8ucXplwSB28y7v3GuKJL3mRiAfmccc.mp4',
      title: 'Hemma i naturen',
      time: '10 min siden',
      caption: 'Vi börjar med att smälta lite snö på elden'
    },
    {
      src: 'SnapInsta.to_AQNAA6XSsiZrXgJPMYQEaiN7rcK7bvE5r8A04hu2z5EyID9HhnVrFcC3kzs4ZTWhEhN50zNfcbYhp3ehYATYPSq9oN7ZLS7pXuvZ3b4.mp4',
      title: 'Vintertur i fjällen',
      time: '35 min siden',
      caption: 'Perfekt lager på lager-system'
    },
    {
      src: 'SnapInsta.to_AQOXPGgcx70qtQNQ9pjM5Hc0mL6XLphl9_5AXEXz4E7NEPraInD-vHxiaZuNC-JvvC3kzDT5_gla2Xvs9ROfXjQNs7WpQk7bypZQiJk.mp4',
      title: 'Morgon vid sjön',
      time: '1 tim sedan',
      caption: 'Kaffet smakar bäst utomhus'
    },
    {
      src: 'SnapInsta.to_AQP9ZDSEZS3pE4-mPx2REq79l4nIFBL9fHAd70lai536YfaIbi4wvZfw7Yi63NRpjXN9aIwYYYp_aCoZC61In5Xb6XRZxK7E2jAO-QU.mp4',
      title: 'Jakten börjar',
      time: '2 tim sedan',
      caption: 'Tidigt uppe — det är värt det'
    },
    {
      src: 'SnapInsta.to_AQPKH78_nvSITJpunsEZkA24d1cEYbtMZo0oYIZizjgG8enZBM_pxKzITXMsidQL4eWDQa0MpGGUqIE-Ihxey76GrndSuY2HXdcfIgI.mp4',
      title: 'Tältliv',
      time: '3 tim sedan',
      caption: 'Allt du behöver för en natt ute'
    }
  ];

  const viewport = document.getElementById('videoViewport');
  const thumbContainer = document.getElementById('thumbContainer');
  const titleEl = document.getElementById('shortsTitle');
  const timeEl = document.getElementById('shortsTime');
  const muteBtn = document.getElementById('muteBtn');
  const navUp = document.getElementById('navUp');
  const navDown = document.getElementById('navDown');

  let currentIndex = 0;
  let isMuted = true;

  // Build slides
  videos.forEach((v, i) => {
    const slide = document.createElement('div');
    slide.className = 'video-slide';
    slide.innerHTML = `
      <div class="video-card">
        <video src="${v.src}" muted loop playsinline preload="${i < 2 ? 'auto' : 'metadata'}"></video>
        <div class="video-gradient"></div>
        <div class="video-captions"><p>${v.caption}</p></div>
        <div class="video-progress"><div class="video-progress-fill"></div></div>
      </div>
    `;
    viewport.appendChild(slide);
  });

  // Build thumbnails (show 3 at a time around current)
  function buildThumbs() {
    thumbContainer.innerHTML = '';
    const indices = getThumbIndices();
    indices.forEach(i => {
      const thumb = document.createElement('div');
      thumb.className = 'shorts-thumb' + (i === currentIndex ? ' active' : '');
      thumb.innerHTML = `<video src="${videos[i].src}" muted preload="metadata"></video>`;
      thumb.addEventListener('click', () => goToSlide(i));
      // Seek thumbnail to 1s for a preview frame
      const tv = thumb.querySelector('video');
      tv.addEventListener('loadeddata', () => { tv.currentTime = 1; });
      thumbContainer.appendChild(thumb);
    });
  }

  function getThumbIndices() {
    const result = [];
    for (let offset = -1; offset <= 1; offset++) {
      const idx = currentIndex + offset;
      if (idx >= 0 && idx < videos.length) result.push(idx);
    }
    return result;
  }

  // Scroll to slide
  function goToSlide(index) {
    if (index < 0 || index >= videos.length) return;
    const slides = viewport.querySelectorAll('.video-slide');
    slides[index].scrollIntoView({ behavior: 'smooth', block: 'center' });
  }

  // Detect which slide is visible via IntersectionObserver
  const observer = new IntersectionObserver((entries) => {
    entries.forEach(entry => {
      if (entry.isIntersecting && entry.intersectionRatio > 0.6) {
        const slides = Array.from(viewport.querySelectorAll('.video-slide'));
        const idx = slides.indexOf(entry.target);
        if (idx !== -1 && idx !== currentIndex) {
          currentIndex = idx;
          onSlideChange();
        }
      }
    });
  }, { root: viewport, threshold: [0.6] });

  viewport.querySelectorAll('.video-slide').forEach(s => observer.observe(s));

  function onSlideChange() {
    const v = videos[currentIndex];
    titleEl.textContent = v.title;
    timeEl.textContent = v.time;
    buildThumbs();

    // Play current, pause others
    const allVideos = viewport.querySelectorAll('video');
    allVideos.forEach((vid, i) => {
      if (i === currentIndex) {
        vid.play().catch(() => {});
        vid.muted = isMuted;
      } else {
        vid.pause();
        vid.currentTime = 0;
      }
    });
  }

  // Progress bar update
  function updateProgress() {
    const allSlides = viewport.querySelectorAll('.video-slide');
    allSlides.forEach((slide, i) => {
      const vid = slide.querySelector('video');
      const fill = slide.querySelector('.video-progress-fill');
      if (vid && fill && vid.duration) {
        const pct = (vid.currentTime / vid.duration) * 100;
        fill.style.width = pct + '%';
      }
    });
    requestAnimationFrame(updateProgress);
  }
  requestAnimationFrame(updateProgress);

  // Nav buttons
  navUp.addEventListener('click', () => goToSlide(currentIndex - 1));
  navDown.addEventListener('click', () => goToSlide(currentIndex + 1));

  // Mute toggle
  muteBtn.addEventListener('click', () => {
    isMuted = !isMuted;
    const currentVid = viewport.querySelectorAll('.video-slide')[currentIndex]?.querySelector('video');
    if (currentVid) currentVid.muted = isMuted;
    muteBtn.style.opacity = isMuted ? '0.5' : '1';
  });

  // Keyboard nav
  document.addEventListener('keydown', (e) => {
    if (e.key === 'ArrowDown' || e.key === 'j') goToSlide(currentIndex + 1);
    if (e.key === 'ArrowUp' || e.key === 'k') goToSlide(currentIndex - 1);
    if (e.key === 'm') muteBtn.click();
  });

  // Init
  buildThumbs();
  // Auto-play first video
  const firstVid = viewport.querySelector('.video-slide video');
  if (firstVid) {
    firstVid.play().catch(() => {});
  }
})();
</script>

</body>
</html>

