  /* Shop the look drawer */
  .shop-overlay {
    position: absolute;
    inset: 0;
    background: rgba(0,0,0,0.5);
    z-index: 50;
    opacity: 0;
    pointer-events: none;
    transition: opacity 0.3s var(--ease-standard);
  }
  .shop-overlay.open {
    opacity: 1;
    pointer-events: auto;
  }

  .shop-drawer {
    position: absolute;
    right: 0;
    top: 0;
    bottom: 0;
    width: 420px;
    background: #fff;
    z-index: 51;
    transform: translateX(100%);
    transition: transform 0.4s var(--ease-snappy);
    display: flex;
    flex-direction: column;
    overflow: hidden;
  }
  .shop-overlay.open .shop-drawer {
    transform: translateX(0);
  }

  .shop-drawer-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 24px 28px 20px;
    border-bottom: 1px solid #e1e1e1;
  }
  .shop-drawer-title {
    font-weight: 600;
    font-size: 18px;
    letter-spacing: 0.01em;
  }
  .shop-drawer-close {
    background: none;
    border: none;
    cursor: pointer;
    padding: 4px;
    opacity: 0.5;
    transition: opacity 0.15s;
  }
  .shop-drawer-close:hover { opacity: 1; }

  .shop-drawer-items {
    flex: 1;
    overflow-y: auto;
    padding: 20px 28px;
    display: flex;
    flex-direction: column;
    gap: 20px;
  }

  .shop-product {
    display: flex;
    gap: 16px;
    align-items: flex-start;
  }
  .shop-product-img {
    width: 100px;
    height: 120px;
    border-radius: 12px;
    background: #f0f0ef;
    flex-shrink: 0;
    overflow: hidden;
    display: flex;
    align-items: center;
    justify-content: center;
  }
  .shop-product-img img {
    width: 100%;
    height: 100%;
    object-fit: cover;
  }
  .shop-product-info {
    flex: 1;
    display: flex;
    flex-direction: column;
    gap: 4px;
    padding-top: 4px;
  }
  .shop-product-brand {
    font-size: 11px;
    font-weight: 500;
    letter-spacing: 0.06em;
    text-transform: uppercase;
    color: #888;
  }
  .shop-product-name {
    font-weight: 500;
    font-size: 14px;
    line-height: 1.3;
    color: #000;
  }
  .shop-product-price {
    font-weight: 600;
    font-size: 15px;
    color: #000;
    margin-top: 4px;
  }
  .shop-product-btn {
    margin-top: 8px;
    background: var(--green);
    color: #fff;
    border: none;
    border-radius: 10px;
    padding: 10px 0;
    font-family: 'Bagoss Extended', system-ui, sans-serif;
    font-weight: 500;
    font-size: 13px;
    letter-spacing: 0.02em;
    cursor: pointer;
    text-align: center;
    transition: background 0.15s var(--ease-standard);
  }
  .shop-product-btn:hover { background: #1a5c34; }
