function openShop() {
  const v = feed[currentIndex];
  if (!v.products || !v.products.length) return;
  shopItems.innerHTML = v.products.map(p => `
    <div class="shop-product">
      <div class="shop-product-img">
        <div style="width:100%;height:100%;background:${p.color};opacity:0.18"></div>
      </div>
      <div class="shop-product-info">
        <span class="shop-product-brand">${p.brand}</span>
        <span class="shop-product-name">${p.name}</span>
        <span class="shop-product-price">${p.price}</span>
        <button class="shop-product-btn">Legg i handlekurv</button>
      </div>
    </div>
  `).join('');
  shopOverlay.classList.add('open');
}

