// Product bubble + CTA
const hasProducts = v.products && v.products.length > 0;
shopOverlay.classList.remove('open');

if (hasProducts) {
  // Pick first product with an image, or just the first product
  const featured = v.products.find(p => p.img) || v.products[0];
  productBubbleImg.innerHTML = featured.img
    ? `<img src="${featured.img}" alt="${featured.name}">`
    : `<div style="width:100%;height:100%;background:rgba(255,255,255,0.06)"></div>`;
  productBubbleLabel.textContent = 'Used: ' + featured.brand + ' ' + featured.name;

  // Re-trigger animations by removing and re-adding class
  productBubble.classList.remove('visible');
  shopCta.style.opacity = '0';
  shopCta.style.transform = 'translateX(-20px)';
  shopCta.style.display = '';
  void productBubble.offsetWidth; // force reflow
  productBubble.classList.add('visible');
} else {
  productBubble.classList.remove('visible');
  shopCta.style.display = 'none';
}

