/* ============================================
   LEFT INFO PANEL — Motion System

   Easing vocabulary (from vault/premium-motion-patterns):
   - expo-out:          fast burst → silky decel. Entrances.
   - overshoot:         goes past target, settles. Small UI.
   - overshoot-strong:  dramatic past-target. Hero moments.
   - smooth-decel:      gentle, no drama. Layout shifts.

   Orchestration rules:
   - Overlap aggressively: 80–150ms offsets
   - Quick fades (0.1–0.2s), slow transforms (0.5–1s)
   - Opacity leads, transform follows
   - Each layer gets its own easing
   ============================================ */

.shorts-info {
  position: absolute;
  left: 45px;
  bottom: 50%;
  transform: translateY(50%);
  z-index: 10;
  display: flex;
  flex-direction: column;
}

/* GPU compositing for all animated children */
.shorts-info-title,
.shorts-info-time,
.product-bubble-img,
.product-bubble-label,
.shorts-info-cta {
  will-change: transform, opacity;
}

/* ---- Title ---- */
.shorts-info-title {
  font-family: 'Bagoss Extended', system-ui, sans-serif;
  font-weight: 600;
  font-size: 24px;
  line-height: 0.92;
  color: #fff;
  max-width: 200px;
  margin-bottom: 10px;
  opacity: 0;
  transform: translateY(18px);
}
.shorts-info.animate .shorts-info-title {
  animation: titleIn 0.9s var(--ease-expo-out) 0s forwards;
}

/* ---- Timestamp ---- */
.shorts-info-time {
  font-family: 'Bagoss Extended', system-ui, sans-serif;
  font-weight: 300;
  font-size: 16px;
  color: #fff;
  margin-bottom: 26px;
  opacity: 0;
  transform: translateY(12px);
  /* Reactive spacing: when bubble pushes in, margin transitions smoothly */
  transition: margin-bottom 0.8s var(--ease-smooth-decel);
}
.shorts-info.animate .shorts-info-time {
  animation: timeIn 0.7s var(--ease-expo-out) 0.1s forwards;
}
.shorts-info.has-product .shorts-info-time {
  margin-bottom: 22px;
}

/* ---- Product bubble container ---- */
.product-bubble {
  display: flex;
  flex-direction: column;
  gap: 10px;
  margin-bottom: 0;
  max-height: 0;
  overflow: hidden;
  /* The container expands smoothly — this is what "pushes" the title/time up */
  transition: max-height 0.85s var(--ease-expo-out) 0.2s,
              margin-bottom 0.85s var(--ease-expo-out) 0.2s;
}
.product-bubble.visible {
  max-height: 240px;
  margin-bottom: 18px;
}

/* ---- Product thumbnail ---- */
.product-bubble-img {
  width: 135px;
  height: 138px;
  border-radius: 23px;
  background: #404040;
  overflow: hidden;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 16px 32px 14px;
  opacity: 0;
  transform: scale(0.4) translateY(12px);
}
.product-bubble.visible .product-bubble-img {
  animation: bubbleIn 1s var(--ease-overshoot-strong) 0.3s forwards;
}
.product-bubble-img img {
  width: 100%;
  height: 100%;
  object-fit: contain;
  border-radius: 20px;
}

/* ---- Product label ---- */
.product-bubble-label {
  font-family: 'Bagoss Extended', system-ui, sans-serif;
  font-weight: 300;
  font-size: 13px;
  color: rgba(255,255,255,0.7);
  opacity: 0;
  transform: translateX(-18px);
}
.product-bubble.visible .product-bubble-label {
  animation: labelIn 0.6s var(--ease-expo-out) 0.7s forwards;
}

/* ---- CTA button ---- */
.shorts-info-cta {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  background: #AFCC95;
  color: #000;
  font-family: 'Bagoss Extended', system-ui, sans-serif;
  font-weight: 400;
  font-size: 14px;
  line-height: 1;
  padding: 8px 20px;
  border-radius: 15px;
  border: none;
  cursor: pointer;
  width: fit-content;
  opacity: 0;
  transform: translateX(-14px) scale(0.95);
  transition: background 0.25s var(--ease-smooth-decel),
              box-shadow 0.25s var(--ease-smooth-decel);
}
.product-bubble.visible + .shorts-info-cta {
  animation: ctaIn 0.7s var(--ease-overshoot) 0.85s forwards;
}
.shorts-info-cta:hover {
  background: #c2daad;
  box-shadow: 0 2px 12px rgba(175, 204, 149, 0.3);
}

/* ============================================
   KEYFRAMES

   Principle: opacity resolves in the first 20-30%,
   transform carries through to 100%. This creates
   the "appears instantly, then settles into place"
   feel of spring physics without actual springs.
   ============================================ */

/* Title: vertical slide, expo-out. Longest duration = sets the tone. */
@keyframes titleIn {
  0%   { opacity: 0;   transform: translateY(18px); }
  18%  { opacity: 1; }
  100% { opacity: 1;   transform: translateY(0); }
}

/* Timestamp: follows title closely (100ms offset), shorter travel */
@keyframes timeIn {
  0%   { opacity: 0;   transform: translateY(12px); }
  22%  { opacity: 0.8; }
  100% { opacity: 0.8; transform: translateY(0); }
}

/* Bubble: the hero moment.
   Uses overshoot-strong — goes ~42% past target then settles.
   Scale + slight Y creates a "rising into place" feel.
   Rotation is gone — it was adding noise, not personality. */
@keyframes bubbleIn {
  0%   { opacity: 0;   transform: scale(0.4) translateY(12px); }
  15%  { opacity: 1; }
  100% { opacity: 1;   transform: scale(1) translateY(0); }
}

/* Label: horizontal slide. Short, snappy, no drama.
   Starts as bubble hits ~70% of its animation. */
@keyframes labelIn {
  0%   { opacity: 0;   transform: translateX(-18px); }
  20%  { opacity: 0.7; }
  100% { opacity: 0.7; transform: translateX(0); }
}

/* CTA: scale + slide, overshoot easing gives it a subtle bounce.
   Last element — lands just as everything else settles. */
@keyframes ctaIn {
  0%   { opacity: 0;   transform: translateX(-14px) scale(0.95); }
  20%  { opacity: 1; }
  100% { opacity: 1;   transform: translateX(0) scale(1); }
}

