/* --- Shared motion primitives --- */
.shorts-info-title,
.shorts-info-time,
.product-bubble-img,
.product-bubble-label,
.shorts-info-cta {
  will-change: transform, opacity, filter;
}

/* Title */
.shorts-info-title {
  font-family: 'Bagoss Extended', system-ui, sans-serif;
  font-weight: 600;
  font-size: 24px;
  line-height: 0.92;
  color: #fff;
  max-width: 200px;
  margin-bottom: 10px;
  transform: translateY(14px) translateX(-10px);
  opacity: 0;
  filter: blur(6px);
  transition: margin-bottom 0.6s cubic-bezier(0.16, 1, 0.3, 1);
}
.shorts-info.animate .shorts-info-title {
  animation: textReveal 0.8s cubic-bezier(0.16, 1, 0.3, 1) 0.05s forwards;
}

/* Timestamp */
.shorts-info-time {
  font-family: 'Bagoss Extended', system-ui, sans-serif;
  font-weight: 300;
  font-size: 16px;
  color: #fff;
  opacity: 0;
  margin-bottom: 0;
  transform: translateY(10px) translateX(-8px);
  filter: blur(4px);
  transition: margin-bottom 0.6s cubic-bezier(0.16, 1, 0.3, 1);
}
.shorts-info.animate .shorts-info-time {
  animation: textReveal 0.7s cubic-bezier(0.16, 1, 0.3, 1) 0.18s forwards;
}
/* When bubble appears, time gets pushed up with breathing room */
.shorts-info.has-product .shorts-info-time {
  margin-bottom: 22px;
}
.shorts-info:not(.has-product) .shorts-info-time {
  margin-bottom: 26px;
}

/* Product bubble */
.product-bubble {
  display: flex;
  flex-direction: column;
  gap: 10px;
  margin-bottom: 0;
  max-height: 0;
  overflow: hidden;
  transition: max-height 0.7s cubic-bezier(0.16, 1, 0.3, 1) 0.25s,
              margin-bottom 0.7s cubic-bezier(0.16, 1, 0.3, 1) 0.25s;
}
.product-bubble.visible {
  max-height: 220px;
  margin-bottom: 18px;
}

.product-bubble-img {
  width: 135px;
  height: 138px;
  border-radius: 23px;
  background: #404040;
  overflow: hidden;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 16px 32px 14px;
  transform: scale(0.3) rotate(-6deg) translateY(20px);
  opacity: 0;
  filter: blur(12px);
}
.product-bubble.visible .product-bubble-img {
  animation: bubblePop 0.9s cubic-bezier(0.34, 1.4, 0.64, 1) 0.35s forwards;
}
.product-bubble-img img {
  width: 100%;
  height: 100%;
  object-fit: contain;
  border-radius: 20px;
}

.product-bubble-label {
  font-family: 'Bagoss Extended', system-ui, sans-serif;
  font-weight: 300;
  font-size: 13px;
  color: rgba(255,255,255,0.7);
  transform: translateX(-24px) translateY(4px);
  opacity: 0;
  filter: blur(6px);
}
.product-bubble.visible .product-bubble-label {
  animation: labelSlide 0.7s cubic-bezier(0.16, 1, 0.3, 1) 0.75s forwards;
}

