.shorts-info-cta {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  background: #AFCC95;
  color: #000;
  font-family: 'Bagoss Extended', system-ui, sans-serif;
  font-weight: 400;
  font-size: 14px;
  line-height: 1;
  padding: 8px 20px;
  border-radius: 15px;
  border: none;
  cursor: pointer;
  width: fit-content;
  transform: translateX(-20px) scale(0.92);
  opacity: 0;
  filter: blur(6px);
  transition: background 0.2s cubic-bezier(0.16, 1, 0.3, 1),
