}
.product-bubble.visible + .shorts-info-cta {
  animation: ctaReveal 0.65s cubic-bezier(0.34, 1.3, 0.64, 1) 0.95s forwards;
}
.shorts-info-cta:hover {
  background: #c2daad;
  transform: translateX(0) scale(1.03);
}

