/* Text: slide up + right, deblur, fade in — soft spring deceleration */
@keyframes textReveal {
  0% {
    transform: translateY(14px) translateX(-10px);
    opacity: 0;
    filter: blur(6px);
  }
  35% {
    opacity: 0.7;
    filter: blur(1px);
  }
  100% {
    transform: translateY(0) translateX(0);
    opacity: 1;
    filter: blur(0px);
  }
}

/* Bubble: scale from small + rotated, spring overshoot, settle with micro-bounce */
@keyframes bubblePop {
  0% {
    transform: scale(0.3) rotate(-6deg) translateY(20px);
    opacity: 0;
    filter: blur(12px);
