  }
  80% {
    transform: scale(1.02) rotate(0.2deg) translateY(-1px);
  }
  100% {
    transform: scale(1) rotate(0deg) translateY(0);
    opacity: 1;
    filter: blur(0px);
  }
}

/* Label: slide x with subtle y drift, deblur */
@keyframes labelSlide {
  0% {
    transform: translateX(-24px) translateY(4px);
    opacity: 0;
    filter: blur(6px);
  }
  30% {
    filter: blur(1px);
  }
  60% {
    transform: translateX(2px) translateY(0);
    opacity: 1;
  }
  100% {
    transform: translateX(0) translateY(0);
    opacity: 0.7;
    filter: blur(0px);
  }
}

/* CTA: slide in + scale up, slight spring overshoot */
@keyframes ctaReveal {
  0% {
    transform: translateX(-20px) scale(0.92);
    opacity: 0;
    filter: blur(6px);
  }
  40% {
    opacity: 1;
    filter: blur(0px);
  }
  70% {
    transform: translateX(3px) scale(1.02);
  }
  100% {
    transform: translateX(0) scale(1);
    opacity: 1;
    filter: blur(0px);
  }
}

