/* ============================================
   KEYFRAMES

   Principle: opacity resolves in the first 20-30%,
   transform carries through to 100%. This creates
   the "appears instantly, then settles into place"
   feel of spring physics without actual springs.
   ============================================ */

/* Title: vertical slide, expo-out. Longest duration = sets the tone. */
@keyframes titleIn {
  0%   { opacity: 0;   transform: translateY(18px); }
  18%  { opacity: 1; }
  100% { opacity: 1;   transform: translateY(0); }
}

/* Timestamp: follows title closely (100ms offset), shorter travel */
@keyframes timeIn {
  0%   { opacity: 0;   transform: translateY(12px); }
  22%  { opacity: 0.8; }
  100% { opacity: 0.8; transform: translateY(0); }
}

/* Bubble: the hero moment.
   Uses overshoot-strong — goes ~42% past target then settles.
   Scale + slight Y creates a "rising into place" feel.
   Rotation is gone — it was adding noise, not personality. */
@keyframes bubbleIn {
  0%   { opacity: 0;   transform: scale(0.4) translateY(12px); }
  15%  { opacity: 1; }
  100% { opacity: 1;   transform: scale(1) translateY(0); }
}

/* Label: horizontal slide. Short, snappy, no drama.
   Starts as bubble hits ~70% of its animation. */
@keyframes labelIn {
  0%   { opacity: 0;   transform: translateX(-18px); }
  20%  { opacity: 0.7; }
  100% { opacity: 0.7; transform: translateX(0); }
}

/* CTA: scale + slide, overshoot easing gives it a subtle bounce.
   Last element — lands just as everything else settles. */
@keyframes ctaIn {
  0%   { opacity: 0;   transform: translateX(-14px) scale(0.95); }
  20%  { opacity: 1; }
  100% { opacity: 1;   transform: translateX(0) scale(1); }
}

