// Persistent thumbnail slots with canvas
const thumbSlots = [
  document.getElementById('thumb0'),
  document.getElementById('thumb1'),
  document.getElementById('thumb2'),
];
const thumbSrcs = ['', '', ''];

// Frame cache: src → ImageBitmap (captured once, reused forever)
const frameCache = new Map();
const framePending = new Set();

function captureFrame(src) {
  if (frameCache.has(src) || framePending.has(src)) return;
  framePending.add(src);
  const v = document.createElement('video');
  v.muted = true;
  v.preload = 'auto';
  v.crossOrigin = 'anonymous';
  v.src = src;
  v.addEventListener('loadeddata', () => {
    v.currentTime = 1;
  }, { once: true });
  v.addEventListener('seeked', () => {
    createImageBitmap(v, { resizeWidth: 184, resizeHeight: 190 }).then(bmp => {
      frameCache.set(src, bmp);
      framePending.delete(src);
      v.src = ''; // release
      // Repaint any thumbs waiting for this frame
      paintThumbs();
    }).catch(() => { framePending.delete(src); });
  }, { once: true });
}

function paintThumbs() {
  thumbSlots.forEach((slot, i) => {
    const src = thumbSrcs[i];
    if (!src) return;
    const bmp = frameCache.get(src);
    if (!bmp) return;
    const canvas = slot.querySelector('canvas');
    const ctx = canvas.getContext('2d');
    canvas.width = 184;
    canvas.height = 190;
    ctx.drawImage(bmp, 0, 0, 184, 190);
  });
}

thumbSlots.forEach(slot => {
  slot.addEventListener('click', () => {
    const idx = parseInt(slot.dataset.feedIndex, 10);
    if (!isNaN(idx)) goToSlide(idx);
  });
});

function updateThumbs() {
  const indices = [];
  for (let offset = -1; offset <= 1; offset++) {
    const idx = currentIndex + offset;
    if (idx >= 0 && idx < feed.length) indices.push(idx);
    else indices.push(null);
  }

  indices.forEach((feedIdx, i) => {
    const slot = thumbSlots[i];
    if (feedIdx === null) {
      slot.classList.add('exiting');
      slot.classList.remove('active');
      slot.dataset.feedIndex = '';
      return;
    }

    const src = feed[feedIdx].src;
    slot.dataset.feedIndex = feedIdx;
    slot.classList.remove('exiting');

    if (thumbSrcs[i] !== src) {
      thumbSrcs[i] = src;
      captureFrame(src);
      // Paint immediately if cached
      const bmp = frameCache.get(src);
      if (bmp) {
        const canvas = slot.querySelector('canvas');
        const ctx = canvas.getContext('2d');
        canvas.width = 184;
        canvas.height = 190;
        ctx.drawImage(bmp, 0, 0, 184, 190);
      }
    }

    slot.classList.toggle('active', feedIdx === currentIndex);
  });
}

