// Init — first batch shuffled
addBatch();
updateThumbs();
// Set initial state
const firstData = feed[0];
titleEl.textContent = firstData.title;
timeEl.textContent = firstData.time;
infoPanel.classList.add('animate');
if (firstData.products && firstData.products.length) {
  infoPanel.classList.add('has-product');
  const featured = firstData.products.find(p => p.img) || firstData.products[0];
  productBubbleImg.innerHTML = featured.img
