/* Mobile: hide desktop product bubble, show trigger button instead */
body.mobile-mode .product-bubble { display: none !important; }
body.mobile-mode .shorts-info-cta {
  font-size: 13px;
  padding: 8px 16px;
  border-radius: 12px;
  background: rgba(255,255,255,0.15);
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  color: #fff;
  opacity: 0;
  transform: translateY(8px);
}
body.mobile-mode .shorts-info.has-product .shorts-info-cta {
  animation: ctaIn 0.45s var(--ease-overshoot) 0.3s forwards;
}
body.mobile-mode .shorts-info-cta:hover {
  background: rgba(255,255,255,0.22);
  box-shadow: none;
}

/* Mobile product drawer */
.mobile-product-overlay {
  display: none;
  position: absolute;
  inset: 0;
  z-index: 60;
}
body.mobile-mode .mobile-product-overlay { display: block; }
.mobile-product-overlay .overlay-bg {
  position: absolute;
  inset: 0;
  background: rgba(0,0,0,0.4);
  opacity: 0;
  transition: opacity 0.35s var(--ease-expo-out);
  pointer-events: none;
}
.mobile-product-overlay.open .overlay-bg {
  opacity: 1;
  pointer-events: auto;
}
.mobile-product-drawer {
  position: absolute;
  right: 0;
  top: 0;
  bottom: 0;
  width: 280px;
  background: #2a2a2a;
  transform: translateX(100%);
  transition: transform 0.5s var(--ease-expo-out);
  display: flex;
  flex-direction: column;
  padding: 24px 20px;
  gap: 20px;
  overflow-y: auto;
  z-index: 61;
}
.mobile-product-overlay.open .mobile-product-drawer {
  transform: translateX(0);
}
.mobile-drawer-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
}
.mobile-drawer-title {
  font-size: 15px;
  font-weight: 500;
  color: #fff;
}
.mobile-drawer-close {
  background: none;
  border: none;
  cursor: pointer;
  padding: 4px;
  opacity: 0.5;
  transition: opacity 0.2s;
}
.mobile-drawer-close:hover { opacity: 1; }
.mobile-drawer-items {
  display: flex;
  flex-direction: column;
  gap: 16px;
}
.mobile-product-card {
  display: flex;
  flex-direction: column;
  gap: 10px;
  opacity: 0;
  transform: scale(0.4) translateY(10px);
}
.mobile-product-overlay.open .mobile-product-card {
  animation: bubbleIn 0.5s var(--ease-overshoot-strong) forwards;
}
.mobile-product-overlay.open .mobile-product-card:nth-child(1) { animation-delay: 0.15s; }
.mobile-product-overlay.open .mobile-product-card:nth-child(2) { animation-delay: 0.25s; }
.mobile-product-overlay.open .mobile-product-card:nth-child(3) { animation-delay: 0.35s; }
.mobile-product-overlay.open .mobile-product-card:nth-child(4) { animation-delay: 0.45s; }
.mobile-product-card-img {
  width: 100%;
  aspect-ratio: 1;
  border-radius: 16px;
  background: #404040;
  overflow: hidden;
}
.mobile-product-card-img img {
  width: 100%;
  height: 100%;
  object-fit: contain;
}
.mobile-product-card-brand {
  font-size: 10px;
  font-weight: 500;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  color: rgba(255,255,255,0.45);
}
.mobile-product-card-name {
  font-size: 14px;
  font-weight: 500;
  color: #fff;
  line-height: 1.3;
  margin-top: -4px;
}
.mobile-product-card-price {
  font-size: 14px;
  font-weight: 600;
  color: #fff;
}
.mobile-product-card-btn {
  background: #AFCC95;
  color: #000;
  border: none;
  border-radius: 10px;
  padding: 10px;
  font-family: 'Bagoss Extended', system-ui, sans-serif;
  font-weight: 500;
  font-size: 12px;
  cursor: pointer;
  text-align: center;
  transition: background 0.2s var(--ease-smooth-decel);
}
.mobile-product-card-btn:hover { background: #c2daad; }

