  // Mobile product drawer
  const mobileOverlay = document.getElementById('mobileProductOverlay');
  const mobileOverlayBg = document.getElementById('mobileOverlayBg');
  const mobileDrawerClose = document.getElementById('mobileDrawerClose');
  const mobileDrawerItems = document.getElementById('mobileDrawerItems');

  function openMobileDrawer() {
    const v = feed[currentIndex];
    if (!v.products || !v.products.length) return;
    mobileDrawerItems.innerHTML = v.products.map(p => `
      <div class="mobile-product-card">
        <div class="mobile-product-card-img" ${p.thumbBg ? `style="background:${p.thumbBg}"` : ''}>
          ${p.img ? `<img src="${p.img}" alt="${p.name}">` : ''}
        </div>
        <span class="mobile-product-card-brand">${p.brand}</span>
        <span class="mobile-product-card-name">${p.name}</span>
        <span class="mobile-product-card-price">${p.price}</span>
        <button class="mobile-product-card-btn">Legg i handlekurv</button>
      </div>
    `).join('');
    mobileOverlay.classList.add('open');
  }
  function closeMobileDrawer() {
    mobileOverlay.classList.remove('open');
  }
  mobileDrawerClose.addEventListener('click', closeMobileDrawer);
  mobileOverlayBg.addEventListener('click', closeMobileDrawer);

  // CTA opens the right drawer depending on mode
  shopCta.addEventListener('click', () => {
    if (document.body.classList.contains('mobile-mode')) {
      openMobileDrawer();
    } else {
      openShop();
    }
  });

  // Update CTA text based on mode
  function updateCtaText() {
    const isMobile = document.body.classList.contains('mobile-mode');
    shopCta.textContent = isMobile ? 'Se produktene' : 'Shop here';
  }

  // Device toggle
  const btnDesktop = document.getElementById('toggleDesktop');
  const btnMobile = document.getElementById('toggleMobile');
  btnDesktop.addEventListener('click', () => {
    document.body.classList.remove('mobile-mode');
    btnDesktop.classList.add('active');
    btnMobile.classList.remove('active');
    closeMobileDrawer();
    updateCtaText();
  });
  btnMobile.addEventListener('click', () => {
    document.body.classList.add('mobile-mode');
    btnMobile.classList.add('active');
    btnDesktop.classList.remove('active');
    updateCtaText();
  });
})();

