// Track previous active states per slot for animation direction
const thumbActiveState = [false, false, false];

function updateThumbs() {
  const indices = [];
  for (let offset = -1; offset <= 1; offset++) {
    const idx = currentIndex + offset;
    if (idx >= 0 && idx < feed.length) indices.push(idx);
    else indices.push(null);
  }

  indices.forEach((feedIdx, i) => {
    const slot = thumbSlots[i];
    if (feedIdx === null) {
      slot.dataset.feedIndex = '';
      animateThumb(slot, i, false);
      return;
    }

    const src = feed[feedIdx].src;
    slot.dataset.feedIndex = feedIdx;

    if (thumbSrcs[i] !== src) {
      thumbSrcs[i] = src;
      captureFrame(src);
      const bmp = frameCache.get(src);
      if (bmp) {
        const canvas = slot.querySelector('canvas');
        const ctx = canvas.getContext('2d');
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        ctx.drawImage(bmp, 0, 0, canvas.width, canvas.height);
      }
    }

    const isActive = feedIdx === currentIndex;
    animateThumb(slot, i, isActive);
  });
}

function animateThumb(slot, slotIdx, isActive) {
  const wasActive = thumbActiveState[slotIdx];
  thumbActiveState[slotIdx] = isActive;

  // Cancel any running animation
  slot.getAnimations().forEach(a => a.cancel());

  if (isActive && !wasActive) {
    // Scale UP — overshoot easing
    slot.animate([
      { transform: 'scale(0.82)', opacity: 0.3 },
      { transform: 'scale(1.04)', opacity: 1, offset: 0.7 },
      { transform: 'scale(1)', opacity: 1 }
    ], { duration: 550, easing: 'cubic-bezier(0.19, 1, 0.22, 1)', fill: 'forwards' });
  } else if (!isActive && wasActive) {
    // Scale DOWN — smooth decel
    slot.animate([
      { transform: 'scale(1)', opacity: 1 },
      { transform: 'scale(0.82)', opacity: 0.3 }
    ], { duration: 500, easing: 'cubic-bezier(0.19, 1, 0.22, 1)', fill: 'forwards' });
  } else if (isActive) {
    // Was active, still active (slot 1 always) — re-trigger a pulse
    slot.animate([
      { transform: 'scale(0.94)', opacity: 0.85 },
      { transform: 'scale(1.03)', opacity: 1, offset: 0.65 },
      { transform: 'scale(1)', opacity: 1 }
    ], { duration: 450, easing: 'cubic-bezier(0.19, 1, 0.22, 1)', fill: 'forwards' });
  } else {
    // Was inactive, still inactive — subtle settle
    slot.animate([
      { transform: 'scale(0.75)', opacity: 0.15 },
      { transform: 'scale(0.82)', opacity: 0.3 }
    ], { duration: 400, easing: 'cubic-bezier(0.19, 1, 0.22, 1)', fill: 'forwards' });
  }
}

