  const vid = viewport.querySelectorAll('.video-slide')[currentIndex]?.querySelector('video');
  if (vid) vid.pause();
}
function resumeCurrent() {
  const vid = viewport.querySelectorAll('.video-slide')[currentIndex]?.querySelector('video');
  if (vid) vid.play().catch(() => {});
}

shopClose.addEventListener('click', () => { shopOverlay.classList.remove('open'); resumeCurrent(); });
shopOverlay.addEventListener('click', (e) => {
  if (e.target === shopOverlay) { shopOverlay.classList.remove('open'); resumeCurrent(); }

